-fn isIdentChar(c: u8) bool {
-    return (c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or (c >= '0' and c <= '9') or c == '_' or c == '$';
-}
-
-fn skipDeclaration(source: []const u8, pos: *usize) bool {
-    var i = pos.*;
-    var brace_depth: u32 = 0;
-    var found_brace = false;
-
-    while (i < source.len) {
-        const c = source[i];
-        if (c == '{') {
-            brace_depth += 1;
-            found_brace = true;
-        } else if (c == '}') {
-            if (brace_depth > 0) brace_depth -= 1;
-            if (brace_depth == 0 and found_brace) {
-                pos.* = i + 1;
-                return true;
-            }
-        } else if (c == ';' and !found_brace) {
-            pos.* = i + 1;
-            return true;
-        }
-        i += 1;
-    }
-    return false;
-}
-
-fn skipTypeExpr(source: []const u8, pos: *usize) bool {
-    var i = pos.*;
-    var angle_depth: u32 = 0;
-    var paren_depth: u32 = 0;
-    var found_type = false;
-
-    while (i < source.len) {
-        const c = source[i];
-
-        if (c == '<') angle_depth += 1;
-        if (c == '>') {
-            if (angle_depth > 0) {
-                angle_depth -= 1;
-                i += 1;
-                continue;
-            }
-        }
-        if (c == '(') paren_depth += 1;
-        if (c == ')') {
-            if (paren_depth > 0) {
-                paren_depth -= 1;
-                i += 1;
-                continue;
-            }
-            break;
-        }
-
-        if (angle_depth > 0 or paren_depth > 0) {
-            i += 1;
-            continue;
-        }
-
-        if (isIdentChar(c) or c == '|' or c == '&' or c == '[' or c == ']' or c == '.' or c == '?') {
-            found_type = true;
-            i += 1;
-            continue;
-        }
-
-        if (c == ' ' or c == '\t') {
-            i += 1;
-            continue;
-        }
-
-        break;
-    }
-
-    if (found_type) {
-        pos.* = i;
-        return true;
-    }
-    return false;
-}
